import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"绝响之物-绝响","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物-绝响.md","filePath":"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物-绝响.md"}'),o={name:"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物-绝响.md"};function d(_,a,l,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"绝响之物-绝响",tabindex:"-1"},[n("绝响之物-绝响 "),e("a",{class:"header-anchor",href:"#绝响之物-绝响","aria-label":'Permalink to "绝响之物-绝响"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="绝响之物-绝响-1" tabindex="-1">绝响之物-绝响 <a class="header-anchor" href="#绝响之物-绝响-1" aria-label="Permalink to &quot;绝响之物-绝响&quot;">​</a></h1><p>绝响</p><p>这是一台带有立架的，黑红双色的麦克风，所有的声音经过它的处理会扭曲失真，似怨灵的哀嚎，又有傀儡丝抽动的声音。</p><p>幕后人操控，<br> 傀儡空舞梦一场，<br> 线断魂魄丧。</p><p>D+500<br> 武器伤害6L，现在你可以使用决心+表达-歌唱+专注-魔力洞察进行攻击，射程20米，造成物理-音波伤害，这种攻击具有【法破】特性。<br> 这种检定也被称为【和歌】检定，在画面表现上，数道傀儡丝从各处蔓延而出，对敌人进行纠缠的攻击。<br> 逐级提升：</p><p>C+1500<br> 武器伤害提升8L，具有【和歌·出世】特性；上一等级中使用【和歌】检定进行攻击的射程，现在提升至20+【传奇决心*10米】。</p><p>【和歌·出世】：当你进行表达相关检定时，具有9加骰。</p><p>B+2500<br> 武器伤害提升7L，具有【和歌·出世】、【和歌·离尘】特性。<br> 上一等级中使用【和歌】检定进行攻击的射程，现在提升至20+【传奇决心*20米】。</p><p>【和歌·出世】：当你进行表达相关检定时，加骰提升1级处理（最高8加骰）。</p><p>【和歌·离尘】：在【和歌】攻击命中后，目标需要使用意志豁免对抗伤害出目，失败则受到B级命运来源的耗竭影响，立刻损失8点AP，如同在本轮内正常使用了这些AP（即使并没有真正使用）一样处理。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
